function worked_http_ts_caching_validation_5(ageSeconds: number, maxAgeSeconds: number, etag: string | null): { reusable: boolean; revalidate: boolean } {
  if (ageSeconds < 0 || maxAgeSeconds < 0) return { reusable: false, revalidate: false };
  const reusable = ageSeconds <= maxAgeSeconds;
  return { reusable, revalidate: !reusable && etag !== null && etag.length > 0 };
}

